// src/components/Quiz.js
import React, {useEffect, useState, useRef} from "react";
import { useMemo } from "react";


/*
Features implemented:
- Multi-page quiz (one question per page)
- Timer per question with auto-move on timeout
- Progress bar
- Instant correct/wrong feedback
- Scoring system and results summary
- Save/restore state to localStorage
- Animated transitions
- Download results as PDF (requires html2canvas + jspdf)
*/

const STORAGE_KEY = "scan2learn_quiz_state_v1";

function generateMCQ(answer){
  if(!answer || answer.trim()==="") return [];
  // Simple distractors: slice, add suffixes, common short form
  const base = answer.trim();
  const wrong1 = base.length>4 ? base.slice(0,Math.max(1,Math.floor(base.length/2))) : base + "X";
  const wrong2 = base + " related";
  const wrong3 = (base.split(" ").slice(0,1).join("") || base) + " approx";
  const candidates = [base, wrong1, wrong2].filter(Boolean);
  // ensure unique
  const uniq = Array.from(new Set(candidates));
  // Shuffle
  for(let i=uniq.length-1;i>0;i--){
    const j=Math.floor(Math.random()*(i+1));
    [uniq[i],uniq[j]]=[uniq[j],uniq[i]];
  }
  return uniq;
}

export default function Quiz({items, extractedText}) {
  // Normalize items: ensure each has question & answer fields
  const norm = items.map(it => ({ question: it.question||it, answer: it.answer||"" }));

  const [pageIndex,setPageIndex] = useState(0);
  const [selections,setSelections] = useState({}); // {index: selectedOption}
  const [checked,setChecked] = useState({}); // {index: isCorrectTrueFalse}
  const [submitted,setSubmitted] = useState(false);
  const [timeLeft,setTimeLeft] = useState(30); // seconds per question
  const [running,setRunning] = useState(true); // timer running
  const [perQuestionTime,setPerQuestionTime] = useState(30);
  const [itemsPerPage,setItemsPerPage] = useState(1); // multi-page=1
  const [animateKey,setAnimateKey] = useState(0); // trigger CSS animation
  const timerRef = useRef(null);

  // load saved state if exists on mount
  useEffect(()=>{
    try{
      const raw = localStorage.getItem(STORAGE_KEY);
      if(raw){
        const parsed = JSON.parse(raw);
        // make sure parsed is compatible
        if(parsed && parsed.total===norm.length){
          setPageIndex(parsed.pageIndex||0);
          setSelections(parsed.selections||{});
          setChecked(parsed.checked||{});
          setSubmitted(parsed.submitted||false);
          setPerQuestionTime(parsed.perQuestionTime||30);
          setItemsPerPage(parsed.itemsPerPage||1);
          setTimeLeft(parsed.timeLeft||parsed.perQuestionTime||30);
        }
      }
    }catch(e){
      // ignore parse errors
    }
  },[]); // eslint-disable-line

  // save state to localStorage on relevant changes
  useEffect(()=>{
    const st = {
      total: norm.length,
      pageIndex, selections, checked, submitted,
      perQuestionTime, itemsPerPage, timeLeft
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(st));
  },[pageIndex,selections,checked,submitted,perQuestionTime,itemsPerPage,timeLeft]); // eslint-disable-line

  // timer effect
  useEffect(()=>{
    if(!running) return;
    // clear existing
    if(timerRef.current) clearInterval(timerRef.current);
    timerRef.current = setInterval(()=>{
      setTimeLeft(t=>{
        if(t<=1){
          clearInterval(timerRef.current);
          handleTimeout();
          return 0;
        }
        return t-1;
      });
    },1000);
    return ()=>{ if(timerRef.current) clearInterval(timerRef.current); };
  },[pageIndex,running]); // reset when pageIndex or running changes

  // when perQuestionTime changes, reset timeLeft
  useEffect(()=> setTimeLeft(perQuestionTime),[perQuestionTime]);

  const totalQuestions = norm.length;
  const totalPages = Math.ceil(totalQuestions/itemsPerPage);
  const currentQuestionIndex = pageIndex; // pageIndex corresponds to question index in multi-page mode

  function handleSelect(qIndex, option){
    setSelections(prev=>({ ...prev, [qIndex]: option }));
    // immediate check
    const correct = (option === norm[qIndex].answer);
    setChecked(prev=>({ ...prev, [qIndex]: correct }));
  }

  function gotoPage(idx){
    if(idx<0||idx>=totalPages) return;
    setAnimateKey(k=>k+1);
    setPageIndex(idx);
    setTimeLeft(perQuestionTime);
    setRunning(true);
  }

  function handleNext(){
    const next = pageIndex+1;
    if(next < totalPages) gotoPage(next);
  }
  function handlePrev(){
    const prev = pageIndex-1;
    if(prev>=0) gotoPage(prev);
  }

  function handleTimeout(){
    // when timeout, lock current question (if not answered) and move on
    if(selections[currentQuestionIndex] === undefined){
      setChecked(prev=>({ ...prev, [currentQuestionIndex]: false }));
    }
    // auto move
    if(pageIndex < totalPages-1){
      gotoPage(pageIndex+1);
    } else {
      // last page: stop timer
      setRunning(false);
      setSubmitted(true);
    }
  }

  function handleSubmitQuiz(){
    setSubmitted(true);
    setRunning(false);
    if(timerRef.current) clearInterval(timerRef.current);
  }

  function calcScore(){
    let correct=0;
    for(let i=0;i<totalQuestions;i++){
      if(checked[i]) correct++;
      else {
        // if not checked but there's a selection, evaluate now
        if(selections[i] && selections[i] === norm[i].answer) correct++;
      }
    }
    return {correct, total: totalQuestions, percent: Math.round((correct/totalQuestions)*100) || 0};
  }

  function resetQuiz(){
    setSelections({});
    setChecked({});
    setPageIndex(0);
    setSubmitted(false);
    setRunning(true);
    setTimeLeft(perQuestionTime);
    localStorage.removeItem(STORAGE_KEY);
  }

  // download PDF of results (requires html2canvas + jspdf)
  async function downloadPDF(){
    try{
      const html2canvas = window.html2canvas || (await import("html2canvas")).default;
      const { jsPDF } = window.jspdf || (await import("jspdf"));
      const node = document.getElementById("quiz-container");
      if(!node) return alert("Quiz container not found");
      const canvas = await html2canvas(node, { scale:1.8 });
      const imgData = canvas.toDataURL("image/png");
      const pdf = new jsPDF("p","mm","a4");
      const imgProps = pdf.getImageProperties(imgData);
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = (imgProps.height * pdfWidth) / imgProps.width;
      pdf.addImage(imgData, "PNG", 0, 0, pdfWidth, pdfHeight);
      pdf.save("scan2learn_quiz_result.pdf");
    }catch(e){
      console.error(e);
      alert("Download PDF requires html2canvas + jspdf. Run: npm install html2canvas jspdf");
    }
  }

  // UI pieces
  const currentQ = norm[currentQuestionIndex];

  // For multi-page mode, options are MCQ generated from the answer.
  const options = generateMCQ(currentQ ? currentQ.answer : "");

  // CSS styles (inline) with simple transitions
  const cardStyle = {
    background:"white",
    borderRadius:10,
    padding:18,
    marginBottom:14,
    border:"1px solid #e6eef8",
    boxShadow:"0 6px 18px rgba(12,18,46,0.04)",
    transition:"transform 300ms ease, opacity 300ms ease"
  };

  const animStyle = {
    transform: "translateY(0)",
    opacity: 1
  };

  const animOutStyle = {
    transform: "translateY(8px)",
    opacity: 0
  };

  const score = calcScore();

  return (
    <div>
      <div style={{display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:10}}>
        <div>
          <strong style={{fontSize:16}}>Progress</strong>
          <div style={{width:260, height:12, background:"#e6eef8", borderRadius:8, overflow:"hidden", marginTop:8}}>
            <div style={{
              width: `${Math.round(((pageIndex+1)/totalPages)*100)}%`,
              height:"100%",
              background:"#0b61d6",
              transition:"width 300ms ease"
            }} />
          </div>
          <div style={{fontSize:13, color:"#475569", marginTop:6}}>
            Question {pageIndex+1} / {totalPages}
          </div>
        </div>

        <div style={{textAlign:"right"}}>
          <div style={{fontSize:13, color:"#475569"}}>Time left</div>
          <div style={{fontSize:20, fontWeight:700, color: timeLeft <=5 ? "crimson" : "#0b61d6"}}>
            {String(timeLeft).padStart(2,"0")}s
          </div>
        </div>
      </div>

      {/* Settings toolbar */}
      <div style={{display:"flex", gap:12, alignItems:"center", marginBottom:12}}>
        <label style={{fontSize:13, color:"#475569"}}>Time per Q:</label>
        <input type="number" min={5} max={300} value={perQuestionTime}
          onChange={(e)=>{ const v=Math.max(5,Math.min(300,Number(e.target.value)||30)); setPerQuestionTime(v); setTimeLeft(v); }}
          style={{width:80, padding:6, borderRadius:6, border:"1px solid #cbd5e1"}} />

        <label style={{fontSize:13, color:"#475569"}}>Mode:</label>
        <select value={itemsPerPage} onChange={(e)=>{ setItemsPerPage(Number(e.target.value)); setPageIndex(0); setAnimateKey(k=>k+1); }}
          style={{padding:6, borderRadius:6, border:"1px solid #cbd5e1"}}>
          <option value={1}>Multi-page (1 per page)</option>
          <option value={3}>Compact (3 per page)</option>
          <option value={5}>All in one</option>
        </select>

        <button onClick={()=>{ setRunning(r=>!r); }} style={{marginLeft:"auto", padding:"8px 12px", borderRadius:8, border:"none", background:"#0b61d6", color:"white", cursor:"pointer"}}>
          {running ? "Pause" : "Resume"}
        </button>

        <button onClick={()=>{ resetQuiz(); }} style={{padding:"8px 12px", borderRadius:8, border:"1px solid #cbd5e1", background:"white", cursor:"pointer" }}>
          Reset
        </button>
      </div>

      {/* Question card(s) */}
      <div key={animateKey} style={{transition:"all 300ms ease"}}>
        {/** Multi-page: show itemsPerPage questions starting from pageIndex*itemsPerPage
            But we store pageIndex as question index for simplicity (for multi-page with itemsPerPage=1 match). */}
        {
          // compute start
          (() => {
            const start = pageIndex * itemsPerPage;
            const end = Math.min(start + itemsPerPage, totalQuestions);
            const block = [];
            for(let i=start;i<end;i++){
              const q = norm[i];
              const opts = generateMCQ(q.answer);
              block.push(
                <div key={i} style={{ ...cardStyle, marginBottom:12 }}>
                  <div style={{marginBottom:8}}>
                    <strong style={{fontSize:15}}>Q{ i+1 }:</strong> <span style={{marginLeft:8}}>{q.question}</span>
                  </div>

                  {/* show options */}
                  { opts.length>0 ? opts.map((op,oi)=>(
                    <label key={oi} style={{
                      display:"block",
                      padding:"8px",
                      marginTop:8,
                      borderRadius:8,
                      border: selections[i] === op ? "2px solid #0b61d6" : "1px solid #e6eef8",
                      background: selections[i] === op ? "#eef2ff" : "white",
                      cursor:"pointer",
                      transition:"all 180ms ease"
                    }}>
                      <input
                        type="radio"
                        name={`q_${i}`}
                        value={op}
                        checked={selections[i] === op}
                        onChange={()=> handleSelect(i,op)}
                        style={{marginRight:10}}
                      />
                      {op}
                    </label>
                  )) : (
                    <div>
                      <input type="text" value={selections[i] || ""} onChange={(e)=>{ handleSelect(i, e.target.value); }} placeholder="Type answer" style={{width:"100%", padding:8, borderRadius:8, border:"1px solid #e6eef8"}} />
                    </div>
                  )}

                  {/* Instant feedback */}
                  { checked[i] !== undefined && (
                    <div style={{marginTop:10, fontWeight:700, color: checked[i] ? "green" : "crimson" }}>
                      { checked[i] ? "Correct" : `Wrong — Correct: ${q.answer || "(no answer available)"}` }
                    </div>
                  )}
                </div>
              );
            }
            return block;
          })()
        }
      </div>

      {/* Controls */}
      <div style={{display:"flex", justifyContent:"space-between", alignItems:"center", marginTop:8}}>
        <div>
          <button onClick={handlePrev} disabled={pageIndex===0} style={{padding:"8px 14px", borderRadius:8, border:"1px solid #cbd5e1", background:"white", cursor: pageIndex===0 ? "not-allowed" : "pointer"}}>Prev</button>
          <button onClick={handleNext} disabled={pageIndex >= totalPages-1} style={{padding:"8px 14px", borderRadius:8, border:"none", background:"#0b61d6", color:"white", marginLeft:8, cursor: pageIndex >= totalPages-1 ? "not-allowed":"pointer"}}>Next</button>
        </div>

        <div style={{display:"flex", gap:8}}>
          <button onClick={()=>{ setSelections(prev=>({...prev})); setSubmitted(false); setChecked(prev=>({...prev})); }} style={{padding:"8px 12px", borderRadius:8, border:"1px solid #cbd5e1", background:"white"}}>Save progress</button>
          <button onClick={handleSubmitQuiz} style={{padding:"8px 12px", borderRadius:8, border:"none", background:"#059669", color:"white"}}>Submit Quiz</button>
          <button onClick={downloadPDF} style={{padding:"8px 12px", borderRadius:8, border:"none", background:"#0b61d6", color:"white"}}>Download PDF</button>
        </div>
      </div>

      {/* Final summary */}
      { submitted && (
        <div style={{marginTop:18, padding:14, borderRadius:10, background:"#f8faf8", border:"1px solid #d1fae5"}}>
          <h3 style={{marginTop:0}}>Results</h3>
          <div style={{display:"flex", gap:24, alignItems:"center"}}>
            <div>
              <div style={{fontSize:32, fontWeight:800, color:"#059669"}}>{score.correct} / {score.total}</div>
              <div style={{color:"#475569"}}>Correct answers</div>
            </div>
            <div>
              <div style={{fontSize:22, fontWeight:700}}>{score.percent}%</div>
              <div style={{color:"#475569"}}>Score</div>
            </div>
            <div>
              <button onClick={()=>{ resetQuiz(); }} style={{padding:"8px 12px", borderRadius:8, border:"1px solid #cbd5e1", background:"white"}}>Try Again</button>
            </div>
          </div>

          {/* show per-question breakdown */}
          <div style={{marginTop:12}}>
            {norm.map((q,i)=>(
              <div key={i} style={{padding:8, borderRadius:8, background:"white", marginBottom:8, border:"1px solid #e6eef8"}}>
                <div style={{fontWeight:700}}>Q{i+1}: {q.question}</div>
                <div style={{marginTop:6}}>Your answer: <strong>{ selections[i] || "(not answered)" }</strong></div>
                <div>Correct answer: <strong>{ q.answer || "(n/a)" }</strong></div>
                <div style={{marginTop:6, color: checked[i] ? "green" : "crimson", fontWeight:700}}>
                  { checked[i] ? "Correct" : "Wrong" }
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}
